// ================================================
// n8n Function Item 节点代码
// 功能：提取二进制图片转Base64 + 透传原始文字信息 + 清洗output数据
// ================================================

// 1. 获取当前项的原始 JSON 数据（透传上游文字信息）
const originalJson = $input.item.json;

// 2. 获取所有输入项并提取 Base64 列表
const items = $input.all();
const base64_list = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  if (item.binary) {
    for (const key of Object.keys(item.binary)) {
      try {
        const buffer = await this.helpers.getBinaryDataBuffer(i, key);
        base64_list.push({
          mime_type: item.binary[key].mimeType || 'image/png',
          data: buffer.toString('base64')
        });
      } catch (error) {
        console.error(`读取二进制字段 ${key} 失败:`, error);
      }
    }
  }
}

// 3. 清洗 output 数据中的特殊字符
let cleanedOutput = '';
if (originalJson?.inputData?.output) {
  const rawOutput = originalJson.inputData.output;

  cleanedOutput = rawOutput
    .replace(/\\/g, '\\\\')
    .replace(/\"/g, '\\"')
    .replace(/\n/g, '\\n')
    .replace(/\r/g, '\\r')
    .replace(/\t/g, '\\t')
    .trim();

  console.log('output 数据清洗完成');
  console.log('原始长度:', rawOutput.length);
  console.log('清洗后长度:', cleanedOutput.length);
}

// 4. 返回合并后的数据
return [{
  json: {
    base64_list: base64_list,
    total_images: base64_list.length,
    inputData: {
      ...originalJson,
      output: cleanedOutput
    },
    originalOutput: originalJson?.inputData?.output || ''
  }
}];

